// // This module implements a 16-bit register file with 8 registers. It has two read ports and one write port. The read ports allow reading the contents of two registers specified by the read addresses (read_addr1, read_addr2). The write port allows writing data to a register specified by the write address (write_addr) when the write enable signal (write_en) is low.
module reg_file(
    input clk,
    input [2:0] read_addr1,
    input [2:0] read_addr2,
    input [2:0] write_addr,
    input [15:0] write_data,
    input write_en,
    output [15:0] read_data1,
    output [15:0] read_data2
    );

    reg [15:0] registers [7:0];

    always @(posedge clk) begin
        if (write_en) begin
            registers[write_addr] <= write_data;
        end
    end

    assign read_data1 = registers[read_addr1];
    assign read_data2 = registers[read_addr2];
endmodule
